import{_ as a,c as m,o as e,b as t}from"./app.aaa68922.js";const q='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 13","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 13","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","sans":"\u0907\u091A\u094D\u091B\u093E\u0936\u0915\u094D\u0924\u093F\u0930\u0941\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940","trans":"Icch\u0101\u015Baktirum\u0101 kum\u0101r\u012B","tags":"vim-1","date":"2021-02-14T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/1/13.md"}',r={},u=t('<div class="stanza"><a href="#s1.13" id="s1.13" class="num">1.13</a><div class="sans"><p>\u0908\u0926\u0943\u0917\u094D\u092F\u094B\u0917\u092D\u0942\u092E\u093F\u0915\u093E\u0938\u092E\u093E\u092A\u0928\u094D\u0928\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903\u2014</p><blockquote><p><strong>\u0907\u091A\u094D\u091B\u093E\u0936\u0915\u094D\u0924\u093F\u0930\u0941\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940\u0965\u0967\u0969\u0965</strong></p></blockquote><p>\u092F\u094B\u0917\u093F\u0928\u0903 \u092A\u0930\u092D\u0948\u0930\u0935\u0924\u093E\u0902 \u0938\u092E\u093E\u092A\u0928\u094D\u0928\u0938\u094D\u092F \u092F\u093E \u0907\u091A\u094D\u091B\u093E \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0941\u092E\u093E \u092A\u0930\u0948\u0935 \u092A\u093E\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0940 \u0938\u094D\u0935\u093E\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0930\u0942\u092A\u093E \u0938\u093E \u091A \u0915\u0941\u092E\u093E\u0930\u0940 \u0935\u093F\u0936\u094D\u0935\u0938\u0930\u094D\u0917\u0938\u0902\u0939\u093E\u0930\u0915\u094D\u0930\u0940\u0921\u093E\u092A\u0930\u093E \u0915\u0941\u092E\u093E\u0930 \u0915\u094D\u0930\u0940\u0921\u093E\u092F\u093E\u092E\u093F\u0924\u093F \u092A\u093E\u0920\u093E\u0924\u094D\u0964</p><p>\u0905\u0925 \u091A \u0915\u0941\u0902 \u092D\u0947\u0926\u094B\u0924\u094D\u0925\u093E\u092A\u093F\u0915\u093E\u0902 \u092E\u093E\u092F\u093E\u092D\u0942\u092E\u093F\u0902 \u092E\u093E\u0930\u092F\u0924\u094D\u092F\u0928\u0941\u0926\u094D\u092D\u093F\u0928\u094D\u0928\u092A\u094D\u0930\u0938\u0930\u093E\u0902 \u0915\u0930\u094B\u0924\u093F \u0924\u091A\u094D\u091B\u0940\u0932\u093E\u0964 \u0915\u0941\u092E\u093E\u0930\u0940 \u091A \u092A\u0930\u093E\u0928\u0941\u092A\u092D\u094B\u0917\u094D\u092F\u093E \u092D\u094B\u0915\u094D\u0924\u094D\u0930\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u0947\u0928 \u0938\u094D\u092B\u0941\u0930\u0928\u094D\u0924\u0940\u0964</p><p>\u0905\u0925\u0935\u093E \u092F\u0925\u093E \u0909\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940 \u092A\u0930\u093F\u0939\u0943\u0924\u0938\u0930\u094D\u0935\u093E\u0938\u0919\u094D\u0917\u093E \u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0948\u0915\u093E\u0924\u094D\u092E\u094D\u092F\u0938\u093E\u0927\u0928\u093E\u0930\u093E\u0927\u0928\u093E\u092F \u0928\u093F\u0924\u094D\u092F\u094B\u0926\u094D\u092F\u0941\u0915\u094D\u0924\u093E \u0924\u0925\u0948\u0935\u093E\u0938\u094D\u092F\u0947\u091A\u094D\u091B\u0947\u0924\u094D\u092F\u0938\u094D\u092E\u0926\u094D\u0917\u0941\u0930\u0941\u092D\u093F\u0930\u093F\u0924\u094D\u0925\u092E\u0947\u0935 \u092A\u093E\u0920\u094B \u0926\u0943\u0937\u094D\u091F\u094B \u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u0936\u094D\u091A\u0964</p><p>\u0905\u0928\u094D\u092F\u0948\u0938\u094D\u0924\u0941 \u0936\u0915\u094D\u0924\u093F\u0924\u092E\u0947\u0924\u093F \u092A\u0920\u093F\u0924\u094D\u0935\u093E \u091C\u094D\u091E\u093E\u0928\u0915\u094D\u0930\u093F\u092F\u093E\u092A\u0947\u0915\u094D\u0937\u094B\u093D\u0938\u094D\u092F\u093E\u0903 \u092A\u094D\u0930\u0915\u0930\u094D\u0937\u094B \u0935\u094D\u092F\u093E\u0916\u094D\u092F\u093E\u0924\u0903\u0964</p><p>\u090F\u0935\u0902 \u0928 \u0932\u094C\u0915\u093F\u0915\u0935\u0926\u0938\u094D\u092F \u092F\u094B\u0917\u093F\u0928\u0903 \u0938\u094D\u0925\u0942\u0932\u0947\u091A\u094D\u091B\u093E\u092A\u093F \u0924\u0941 \u092A\u0930\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0942\u092A\u0948\u0935 \u0938\u0930\u094D\u0935\u0924\u094D\u0930\u093E\u092A\u094D\u0930\u0924\u093F\u0939\u0924\u093E\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0924\u094D\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u093E \u0926\u0947\u0935\u0940 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u0940\u0928\u093E\u0902 \u0928\u093E\u092E\u0930\u0942\u092A\u0948\u0936\u094D\u091A \u0924\u093F\u0937\u094D\u0920\u0924\u093F \u092F\u094B\u0917\u092E\u093E\u092F\u093E\u092A\u094D\u0930\u0924\u093F\u091A\u094D\u091B\u0928\u094D\u0928\u093E \u0915\u0941\u092E\u093E\u0930\u0940 \u0932\u094B\u0915\u092D\u093E\u0935\u093F\u0928\u0940</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091E\u094D\u091C\u092F\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0947\u093D\u092A\u093F</p><blockquote><p>\u0938\u093E \u092E\u092E\u0947\u091A\u094D\u091B\u093E \u092A\u0930\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0935\u093F\u092F\u0941\u0915\u094D\u0924\u093E \u0938\u094D\u0935\u092D\u093E\u0935\u091C\u093E \u0935\u0939\u094D\u0928\u0947\u0930\u0942\u0937\u094D\u092E\u0947\u0935 \u0935\u093F\u091C\u094D\u091E\u0947\u092F\u093E \u0930\u0936\u094D\u092E\u093F\u0930\u0942\u092A\u093E \u0930\u0935\u0947\u0930\u093F\u0935\u0965<br> \u0938\u0930\u094D\u0935\u0938\u094D\u092F \u091C\u0917\u0924\u094B \u0935\u093E\u092A\u093F \u0938\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0915\u093E\u0930\u0923\u093E\u0924\u094D\u092E\u093F\u0915\u093E\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0926\u0947\u0924\u0924\u094D</p><blockquote><p>\u0928 \u0939\u0940\u091A\u094D\u091B\u093E\u0928\u094B\u0926\u0928\u0938\u094D\u092F\u093E\u092F\u0902 \u092A\u094D\u0930\u0947\u0930\u0915\u0924\u094D\u0935\u0947\u0928 \u0935\u0930\u094D\u0924\u0924\u0947 \u0905\u092A\u093F \u0924\u094D\u0935\u093E\u0924\u094D\u092E\u092C\u094D\u0932\u0938\u094D\u092A\u0930\u094D\u0936\u093E\u0924\u094D\u092A\u0941\u0930\u0941\u0937\u0938\u094D\u0924\u0924\u094D\u0938\u092E\u094B \u092D\u0935\u0947\u0924\u094D</p></blockquote><p>\u0907\u0924\u093F \u0915\u093E\u0930\u093F\u0915\u092F\u093E \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0965\u0967\u0969\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5Bgyogabh\u016Bmik\u0101sam\u0101pannasy\u0101sya yogina\u1E25\u2014</p><blockquote><p><strong>Icch\u0101\u015Baktirum\u0101 kum\u0101r\u012B||13||</strong></p></blockquote><p>Yogina\u1E25 parabhairavat\u0101\u1E41 sam\u0101pannasya y\u0101 icch\u0101 s\u0101 \u015Baktirum\u0101 paraiva p\u0101rame\u015Bvar\u012B sv\u0101tantryar\u016Bp\u0101 s\u0101 ca kum\u0101r\u012B vi\u015Bvasargasa\u1E41h\u0101rakr\u012B\u1E0D\u0101par\u0101 kum\u0101ra kr\u012B\u1E0D\u0101y\u0101miti p\u0101\u1E6Dh\u0101t|</p><p>Atha ca ku\u1E41 bhedotth\u0101pik\u0101\u1E41 m\u0101y\u0101bh\u016Bmi\u1E41 m\u0101rayatyanudbhinnaprasar\u0101\u1E41 karoti tacch\u012Bl\u0101| Kum\u0101r\u012B ca par\u0101nupabhogy\u0101 bhoktraik\u0101tmyena sphurant\u012B|</p><p>Athav\u0101 yath\u0101 um\u0101 kum\u0101r\u012B parih\u1E5Btasarv\u0101sa\u1E45g\u0101 mahe\u015Bvaraik\u0101tmyas\u0101dhan\u0101r\u0101dhan\u0101ya nityodyukt\u0101 tathaiv\u0101syecchetyasmadgurubhiritthameva p\u0101\u1E6Dho d\u1E5B\u1E63\u1E6Do vy\u0101khy\u0101ta\u015Bca|</p><p>Anyaistu \u015Baktitameti pa\u1E6Dhitv\u0101 j\xF1\u0101nakriy\u0101pek\u1E63o&#39;sy\u0101\u1E25 prakar\u1E63o vy\u0101khy\u0101ta\u1E25|</p><p>Eva\u1E41 na laukikavadasya yogina\u1E25 sth\u016Blecch\u0101pi tu par\u0101 \u015Baktir\u016Bpaiva sarvatr\u0101pratihat\u0101| Tadukta\u1E41 \u015Br\u012Bmatsvacchande</p><blockquote><p>S\u0101 dev\u012B sarvadev\u012Bn\u0101\u1E41 n\u0101mar\u016Bpai\u015Bca ti\u1E63\u1E6Dhati Yogam\u0101y\u0101praticchann\u0101 kum\u0101r\u012B lokabh\u0101vin\u012B||</p></blockquote><p>iti| \u015Ar\u012Bm\u1E5Btyu\xF1jayabha\u1E6D\u1E6D\u0101rake&#39;pi</p><blockquote><p>S\u0101 mamecch\u0101 par\u0101 \u015Baktiraviyukt\u0101 svabh\u0101vaj\u0101 Vahner\u016B\u1E63meva vij\xF1ey\u0101 ra\u015Bmir\u016Bp\u0101 raveriva| Sarvasya jagato v\u0101pi s\u0101 \u015Bakti\u1E25 k\u0101ra\u1E47\u0101tmik\u0101|</p></blockquote><p>iti| Tadetat</p><blockquote><p>Na h\u012Bcch\u0101nodanasy\u0101ya\u1E41 prerakatvena vartate Api tv\u0101tmablaspar\u015B\u0101tpuru\u1E63astatsamo bhavet||</p></blockquote><p>iti k\u0101rikay\u0101 bha\u1E45gy\u0101 pratip\u0101ditam||13||</p></div><hr><p>\u0423 \u0442\u043E\u0433\u043E _(asya)_Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 <em>(sam\u0101pannasya)</em> \u0442\u0430\u043A\u0438\u0445 <em>(\u012Bd\u1E5Bk)</em> \u0441\u0442\u0430\u0434\u0438\u0439 <em>(bh\u016Bmik\u0101)</em> \u0432 \u0439\u043E\u0433\u0435 <em>(yoga)</em>\u2014</p><blockquote><p>\u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 <em>(icch\u0101 \u015Bakti\u1E25)</em> [\u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u043E\u0433\u043E Yog\u012B - \u044D\u0442\u043E] &quot;\u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 \u015Aiva&quot; <em>(um\u0101)</em> [\u0442\u043E \u0435\u0441\u0442\u044C] Kum\u0101r\u012B <em>(kum\u0101r\u012B)</em>||13||</p></blockquote><p>\u0422\u0430\u043A\u0430\u044F <em>(y\u0101... s\u0101)</em> \u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 <em>(icch\u0101 \u015Bakti\u1E25)</em> Yog\u012B <em>(yogina\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 <em>(sam\u0101pannasya)</em> \u0441\u043E\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u044B (Bhairava) <em>(para-bhairavat\u0101\u1E41)</em> [\u0435\u0441\u0442\u044C) _Um\u0101 --\u0412\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u0438\u0435 \u0428\u0438\u0432\u044B (\u015Aiva)-- <em>(um\u0101)</em>. [\u042D\u0442\u0430 Um\u0101 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0432\u044B\u0441\u0448\u0435\u0439 <em>(par\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0436\u043E\u0439 \u0412\u0441\u0435\u0432\u044B\u0448\u043D\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(p\u0101rama-\u012B\u015Bvar\u012B)</em>, \u0447\u044C\u044F --\u0435\u0435-- \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bp\u0101)</em> - Sv\u0101tantrya, \u0438\u043B\u0438 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u0430\u044F \u0421\u0432\u043E\u0431\u043E\u0434\u0430 <em>(sv\u0101tantrya)</em>. \u0418 <em>(ca)</em>, \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u044E --\u0442.\u0435. \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u0438-- <em>(p\u0101\u1E6Dh\u0101t)</em> &quot;kum\u0101ra kr\u012B\u1E0D\u0101y\u0101m&quot; <em>(kum\u0101ra kr\u012B\u1E0D\u0101y\u0101m iti)</em><sup>1</sup>, \u041E\u043D\u0430 <em>(s\u0101)</em> [\u043D\u0430\u0437\u0432\u0430\u043D\u0430] Kum\u0101r\u012B <em>(kum\u0101r\u012B)</em>, [\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443] \u041E\u043D\u0430 \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0430 <em>(par\u0101)</em> \u0438\u0433\u0440\u0430\u0442\u044C <em>(kr\u012B\u1E0D\u0101)</em> \u0432 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(sarga)</em> [\u0438] \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em> --K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043B \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F &quot;abheda&quot;, \u0442.\u0435. \u043D\u0435 \u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438--|</p><p>\u0418 \u0430\u043D\u0430\u043B\u043E\u0433\u0438\u0447\u043D\u043E <em>(atha ca)</em>, [Kum\u0101r\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u043E\u0439, \u043A\u0442\u043E] \u0432\u044B\u043D\u0443\u0436\u0434\u0430\u0435\u0442 \u0441\u0442\u0430\u0434\u0438\u044E M\u0101y\u0101, [\u0438\u043B\u0438] Ku \u0443\u043C\u0435\u0440\u0435\u0442\u044C <em>(kum... m\u0101y\u0101-bh\u016Bmi\u1E41 m\u0101rayati)</em>. [M\u0101y\u0101] \u043F\u0440\u0438\u0432\u043E\u0434\u0438\u0442 \u043A \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044E <em>(utth\u0101pik\u0101m)</em> bheda, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda)</em>. [\u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 &quot;\u0442\u0430, \u043A\u0442\u043E \u0432\u044B\u043D\u0443\u0436\u0434\u0430\u0435\u0442 \u0441\u0442\u0430\u0434\u0438\u044E M\u0101y\u0101, \u0438\u043B\u0438 Ku \u0443\u043C\u0435\u0440\u0435\u0442\u044C&quot;, \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E] \u041E\u043D\u0430 \u043F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 <em>(an... karoti)</em> \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 [M\u0101y\u0101] <em>(udbhinna-prasar\u0101m)</em>. [\u041F\u043E\u044D\u0442\u043E\u043C\u0443, Kum\u0101r\u012B \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u043E\u0439, \u043A\u0442\u043E \u0438\u043C\u0435\u0435\u0442] \u0442\u0430\u043A\u0443\u044E <em>(tad)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0443, \u0438\u043B\u0438 \u043F\u0440\u0435\u0434\u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(\u015B\u012Bl\u0101)</em><sup>2</sup>. \u0422\u0430\u043A\u0436\u0435 <em>(ca)</em>, Kum\u0101r\u012B <em>(kum\u0101r\u012B)</em> [- \u044D\u0442\u043E \u0442\u0430\u043A\u0430\u044F \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F] \u0441\u0438\u044F\u0435\u0442 \u0432\u043E \u0432\u0441\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B <em>(sphurant\u012B)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(eka-\u0101tmyena)</em> \u0441 Bhokt\u0101, \u0438\u043B\u0438 \u041D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u044E\u0449\u0438\u043C\u0441\u044F --\u0442.\u0435. \u0441 \u015Aiva-- <em>(bhoktr\u0101)</em> [\u0438] \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u043C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u044F <em>(anupabhogy\u0101)</em> \u0434\u043B\u044F \u0434\u0440\u0443\u0433\u0438\u0445 <em>(para)</em> --K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043B \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F &quot;bheda-abheda&quot;, \u0442.\u0435. \u0432 \u0441\u043E\u0447\u0435\u0442\u0430\u043D\u0438\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0438 \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438--|</p><p>\u0418\u043B\u0438 <em>(athav\u0101)</em> \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A <em>(yath\u0101)</em> \u0434\u0435\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u0446\u0430 <em>(kum\u0101r\u012B)</em> Um\u0101 <em>(um\u0101)</em>, \u043E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 <em>(parih\u1E5Bta)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u0435\u0439 <em>(\u0101sa\u1E45g\u0101)</em>, \u0432\u0441\u0435\u0433\u0434\u0430 <em>(nitya)</em> \u0437\u0430\u043D\u044F\u0442\u0430 <em>(udyukt\u0101)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435\u043C <em>(\u0101r\u0101dhan\u0101ya)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0435\u0434\u0435\u0442 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E <em>(s\u0101dhana)</em> \u043A \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0443 <em>(eka-\u0101tmya)</em> \u0441 \u0432\u0435\u043B\u0438\u043A\u0438\u043C <em>(mah\u0101)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C <em>(\u012B\u015Bvara)</em>, \u043F\u043E\u044D\u0442\u043E\u043C\u0443 <em>(tath\u0101)</em> [\u2014 \u044D\u0442\u043E], \u043A\u043E\u043D\u0435\u0447\u043D\u043E <em>(eva)</em>, \u0412\u043E\u043B\u044F <em>(icch\u0101)</em> \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em><sup>3</sup> . \u042D\u0442\u043E \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0435 \u0431\u044B\u043B\u043E \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(iti... ittham eva p\u0101\u1E6Dha\u1E25)</em> \u0443\u0432\u0438\u0434\u0435\u043D\u043E <em>(d\u1E5B\u1E63\u1E6Da\u1E25)</em><sup>4</sup> \u0438 <em>(ca)</em> \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u043E <em>(vy\u0101khy\u0101ta\u1E25)</em> \u043D\u0430\u0448\u0438\u043C\u0438 <em>(asmad)</em> \u0413\u0443\u0440\u0443 --\u0434\u0443\u0445\u043E\u0432\u043D\u044B\u043C\u0438 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430\u043C\u0438-- <em>(gurubhi\u1E25)</em> --K\u1E63emar\u0101ja \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u043B \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F &quot;bheda&quot; , \u0442.\u0435. \u0441 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F--|</p><p>\u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, [\u044D\u0442\u043E\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C] \u0431\u044B\u043B \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043D <em>(pa\u1E6Dhitv\u0101)</em> [\u043A\u0430\u043A] &quot;\u015Baktitam\u0101&quot; --\u0432\u044B\u0441\u0448\u0430\u044F \u0421\u0438\u043B\u0430-- <em>(\u015Baktitam\u0101 iti)</em> \u0434\u0440\u0443\u0433\u0438\u043C\u0438 [\u0430\u0432\u0442\u043E\u0440\u0430\u043C\u0438] <em>(anyai\u1E25)</em>, [\u043F\u043E \u0438\u0445 \u043C\u043D\u0435\u043D\u0438\u044E] \u0433\u043B\u0430\u0432\u0435\u043D\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0441\u0442\u0432\u043E <em>(prakar\u1E63a\u1E25)</em> \u044D\u0442\u043E\u0439 [\u0421\u0438\u043B\u044B \u0412\u043E\u043B\u0438] <em>(asy\u0101\u1E25)</em> \u043D\u0430\u0434 <em>(apek\u1E63a\u1E25)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101na)</em> [\u0438] \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C <em>(kriy\u0101)</em> \u0434\u0435\u0442\u0430\u043B\u044C\u043D\u043E \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F <em>(vy\u0101khy\u0101ta\u1E25)</em> [\u0432 \u0434\u0430\u043D\u043D\u043E\u0439 \u0441\u0443\u0442\u0440\u0435 (s\u016Btra)]<sup>5</sup>|</p><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em>, \u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 <em>(icch\u0101)</em> \u044D\u0442\u043E\u0433\u043E <em>(asya)</em> Yog\u012B <em>(yogina\u1E25)</em> \u043D\u0435 \u0433\u0440\u0443\u0431\u0430\u044F <em>(sth\u016Bl\u0101)</em>, \u043A\u0430\u043A \u044D\u0442\u043E \u0443 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439 <em>(laukika-vat)</em>, \u0430 <em>(api tu)</em> [\u043E\u043D\u0430 \u043F\u043E\u0434\u043E\u0431\u043D\u0430] \u0415\u0435 \u0412\u044B\u0441\u0448\u0435\u0439 \u0421\u0438\u043B\u0435 <em>(par\u0101 \u015Bakti-r\u016Bp\u0101 eva)</em>, \u0442.\u0435. \u0431\u0435\u0441\u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(apratihat\u0101)</em> \u043F\u043E\u0432\u0441\u0435\u043C\u0435\u0441\u0442\u043D\u043E <em>(sarvatra)</em>|</p><p>\u0422\u0430\u043A <em>(tad)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012Bmad)</em> Svacchandatantra <em>(svacchande)</em>:</p><blockquote><p>&quot;\u0411\u043E\u0433\u0438\u043D\u044F <em>(s\u0101 dev\u012B)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 <em>(ti\u1E63\u1E6Dhati)</em> \u043A\u0430\u043A \u0438\u043C\u0435\u043D\u0430 \u0438 \u0444\u043E\u0440\u043C\u044B <em>(n\u0101mar\u016Bpai\u1E25 ca)</em> \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u0431\u043E\u0433\u0438\u043D\u044C <em>(dev\u012Bn\u0101\u1E41)</em>, \u043E\u0441\u0442\u0430\u0435\u0442\u0441\u044F <em>(ti\u1E63\u1E6Dhati)</em> \u0441\u043E\u043A\u0440\u044B\u0442\u043E\u0439 <em>(praticchann\u0101)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C Yogam\u0101y\u0101 --\u0437\u0430\u0432\u0443\u0430\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u0441\u0438\u043B\u043E\u0439, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u0438\u0437 \u0419\u043E\u0433\u0438, \u0438\u043B\u0438 \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C-- <em>(yoga-m\u0101y\u0101)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0435\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u0446\u0435\u0439 <em>(kum\u0101r\u012B)</em> [\u0438] \u0441\u043F\u043E\u0441\u043E\u0431\u0441\u0442\u0432\u0443\u0435\u0442 \u0431\u043B\u0430\u0433\u043E\u0434\u0435\u043D\u0441\u0442\u0432\u0438\u044E <em>(bh\u0101vin\u012B)</em> \u043B\u044E\u0434\u0435\u0439 <em>(loka... iti)</em>&quot;| [\u0421\u043C. Svacchandatantra X, 727]</p></blockquote><p>[\u0418] \u0434\u0430\u0436\u0435 <em>(api)</em> \u0432 \u0441\u0430\u043C\u043E\u0439 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u0439 <em>(\u015Br\u012B... bha\u1E6D\u1E6D\u0101rake)</em> M\u1E5Btyu\xF1jayatantra <em>(m\u1E5Btyu\xF1jaya)</em>:</p><blockquote><p>&quot;\u0412\u044B\u0441\u0448\u0430\u044F <em>(s\u0101.. par\u0101)</em> \u015Aakti <em>(\u015Bakti\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0435\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u0430\u044F --\u0442.\u0435. \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u0430 \u043E\u0442 \u0413\u043E\u0441\u043F\u043E\u0434\u0430-- <em>(aviyukt\u0101)</em> [\u0438] \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F <em>(sva-bh\u0101va-j\u0101)</em>, [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043C\u043E\u0435\u0439 <em>(mama)</em> [\u0441\u0438\u043B\u043E\u0439] \u0412\u043E\u043B\u0438 <em>(icch\u0101)</em>. \u041E\u043D\u0430 \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 <em>(vij\xF1ey\u0101)</em> [\u0432 \u0442\u043E\u043C \u0436\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043A\u043E \u041C\u043D\u0435] \u043A\u0430\u043A <em>(iva... iva)</em> \u0436\u0430\u0440 <em>(\u016B\u1E63m\u0101)</em> \u043A \u043E\u0433\u043D\u044E <em>(vahne\u1E25)</em> [\u0438] \u043B\u0443\u0447\u0438 \u0441\u0432\u0435\u0442\u0430 <em>(ra\u015Bmi-r\u016Bp\u0101)</em> \u043A \u0441\u043E\u043B\u043D\u0446\u0443 <em>(rave\u1E25)</em>. \u042D\u0442\u0430 _(s\u0101)_\u015Aakti <em>(\u015Bakti\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(k\u0101ra\u1E47a-\u0101tmik\u0101)</em> \u0432\u0441\u0435\u0433\u043E \u043C\u0438\u0440\u0430 <em>(sarvasya jagata\u1E25)</em> \u043F\u043E\u0438\u0441\u0442\u0438\u043D\u0435 <em>(v\u0101 api)</em>!&quot; [\u0421\u043C. I, 25-26 \u0432 M\u1E5Btyu\xF1jayatantra]</p></blockquote><p>\u042D\u0442\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(tad etad)</em> [\u0431\u044B\u043B\u0430] \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E <em>(bha\u1E45gy\u0101)</em> \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u0430 <em>(pratip\u0101ditam)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C <em>(k\u0101rikay\u0101)</em> [Spandak\u0101rik\u0101-s]:</p><blockquote><p>&quot;\u042D\u0442\u0430 [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C] <em>(ayam)</em> \u043D\u0435 <em>(na hi)</em> \u0440\u0443\u043A\u043E\u0432\u043E\u0434\u0438\u0442, \u0438\u043B\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 <em>(prerakatvena vartate)</em> \u043F\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(nodanasya)</em> \u0436\u0435\u043B\u0430\u043D\u0438\u0439 <em>(icch\u0101)</em>. \u041D\u043E \u0432\u0441\u0435 \u0436\u0435 <em>(api tu)</em>, \u0432\u0441\u0442\u0443\u043F\u0430\u044F \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(spar\u015B\u0101t)</em> \u0441 \u0421\u0438\u043B\u043E\u0439, \u0438\u043B\u0438 \u042D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 <em>(bala)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u042F <em>(\u0101tma)</em>, [\u044D\u0442\u043E\u0442] \u0447\u0435\u043B\u043E\u0432\u0435\u043A <em>(puru\u1E63a\u1E25)</em> \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F <em>(bhavet)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u043C <em>(sama\u1E25)</em> \u042D\u0442\u043E\u043C\u0443 <em>(tad... iti)</em>&quot;| [\u0421\u043C. Spandak\u0101rik\u0101-s I, 8]</p></blockquote><p>||13||</p><hr><ol><li><p>\u041F\u0435\u0440\u0432\u0430\u044F \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438 \u0441\u0432\u044F\u0437\u0430\u043D\u0430 \u0441 \u0410\u0431\u0445\u0435\u0434\u043E\u0439 (Abheda), \u0438\u043B\u0438 \u041D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C\u044E. \u0424\u0440\u0430\u0437\u0430 &quot;kum\u0101ra kr\u012B\u1E0D\u0101y\u0101m&quot; \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442, \u043A\u0440\u0430\u0442\u043A\u043E, \u0447\u0442\u043E \u0441\u043B\u043E\u0432\u043E &quot;kum\u0101r\u012B&quot; \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 \u043A\u043E\u0440\u043D\u044F &quot;kum\u0101r&quot;, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0438\u0433\u0440\u0430\u0442\u044C \u043A\u0430\u043A \u0440\u0435\u0431\u0435\u043D\u043E\u043A&quot;. \u0422\u0435\u0440\u043C\u0438\u043D &quot;kr\u012B\u1E0D\u0101y\u0101m&quot; (\u043B\u044E\u0431\u044F\u0449\u0438\u0439 \u0438\u0433\u0440\u0443) \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E \u041E\u043D\u0430 \u043B\u044E\u0431\u0438\u0442 \u0438\u0433\u0440\u0430\u0442\u044C (\u043A\u0430\u043A \u0434\u0438\u0442\u044F), \u0438 \u0415\u0435 \u0438\u0433\u0440\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u0438 \u0435\u0435 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u044F \u0432 \u0421\u0435\u0431\u0435 \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430. \u041D\u0443, \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0440\u043E\u0442\u043A\u043E\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0435 \u043D\u0430 \u0441\u0435\u0439\u0447\u0430\u0441, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0443\u0433\u043B\u0443\u0431\u043B\u0435\u043D\u0438\u0435 \u0432 \u044D\u0442\u0443 \u0442\u0435\u043C\u0443 \u043F\u0440\u0438\u0432\u0435\u043B\u043E \u0431\u044B \u043C\u0435\u043D\u044F \u043A \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u044E \u043A\u0430\u043A \u0444\u043E\u0440\u043C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u043A\u043E\u0440\u0435\u043D\u044C &quot;kum\u0101r&quot; \u0438 \u043A\u0430\u043A \u043E\u043D \u0441\u043F\u0440\u044F\u0433\u0430\u0435\u0442\u0441\u044F... \u0430 \u044D\u0442\u043E \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0439 \u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0437\u043D\u0430\u043D\u0438\u044F \u0421\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0447\u0438\u0442\u0430\u0442\u0435\u043B\u0435\u0439 \u043C\u043E\u0433\u0443\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u043C\u0435\u0447\u0442\u0430\u0442\u044C. \u0414\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043E\u0431 \u044D\u0442\u043E\u043C \u0442\u043E\u0433\u0434\u0430, \u0447\u0442\u043E\u0431\u044B \u0432\u0430\u0448\u0438 \u0443\u043C\u044B \u043D\u0435 \u0437\u0430\u043F\u0443\u0442\u0430\u043B\u0438\u0441\u044C \u0435\u0449\u0435 \u0431\u043E\u043B\u044C\u0448\u0435!</p></li><li><p>\u0421\u0432\u044F\u0442\u043E\u0439 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u043B\u043E\u0432\u043E &quot;kum\u0101r\u012B&quot; \u0430\u043A\u0440\u043E\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438: ku + m\u0101r\u012B. \u041F\u043E \u0435\u0433\u043E \u043C\u043D\u0435\u043D\u0438\u044E, &quot;ku&quot; \u0441\u0438\u043C\u0432\u043E\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 M\u0101y\u0101, \u0441\u0438\u043B\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 \u0434\u0443\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C (\u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432), \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A &quot;m\u0101r\u012B&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;m\u0101rayati&quot; - &quot;\u041E\u043D\u0430 \u0437\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u0443\u043C\u0438\u0440\u0430\u0442\u044C&quot;. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, \u0432\u044B\u0441\u0448\u0430\u044F \u0441\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 Yog\u012B \u0435\u0441\u0442\u044C Kum\u0101r\u012B, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u041E\u043D\u0430 \u0440\u0430\u0437\u0440\u0443\u0448\u0430\u0435\u0442 M\u0101y\u0101. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u043E\u043D\u0430 \u043D\u0435 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 M\u0101y\u0101 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u0442\u044C\u0441\u044F. \u0410\u0432\u0442\u043E\u0440 \u043F\u0440\u043E\u044F\u0441\u043D\u0438\u043B \u044D\u0442\u043E, \u0434\u043E\u0431\u0430\u0432\u0438\u0432 &quot;anudbhinnaprasar\u0101\u1E41 karoti&quot; - &quot;\u041E\u043D\u0430 \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0443\u0435\u0442 [M\u0101y\u0101] \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u044E&quot;, \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0437\u0434\u0435\u0441\u044C \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443 \u043E\u0434\u043D\u0430 \u0441 \u0428\u0430\u043A\u0442\u0438, \u0442\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E &quot;\u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0438&quot; \u0447\u0435\u0433\u043E-\u043B\u0438\u0431\u043E \u0432 \u043D\u0435\u0439, \u044D\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C \u0442\u043E, \u0447\u0442\u043E \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435\u043C&quot; \u0432 \u044D\u0442\u043E\u043C \u0418\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0435, \u0442.\u0435. \u0432\u043D\u0443\u0442\u0440\u0438 \u041D\u0435\u0435.</p></li><li><p>\u0410\u0432\u0442\u043E\u0440 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u043B\u043E\u0432\u043E &quot;kum\u0101r\u012B&quot;, \u043A\u0430\u043A &quot;\u0434\u0435\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u0446\u0430&quot;. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, Um\u0101 - \u044D\u0442\u043E \u0445\u043E\u0440\u043E\u0448\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u0436\u0435\u043D\u0430 \u0428\u0438\u0432\u044B \u0432 \u043F\u0443\u0440\u0430\u043D\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0438\u0441\u0442\u043E\u0440\u0438\u044F\u0445, \u0442.\u0435. P\u0101rvat\u012B. \u0421\u0438\u043B\u0430 \u0412\u043E\u043B\u0438 Yog\u012B \u0441\u043E\u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0441 P\u0101rvat\u012B (\u0434\u0435\u0432\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043C\u043E\u043B\u043E\u0434\u043E\u0439 \u0434\u0435\u0432\u0443\u0448\u043A\u043E\u0439, \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u0421\u0432\u043E\u0435\u043C\u0443 \u043C\u0443\u0436\u0443), \u043F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0443 \u043D\u0435\u0435 \u043D\u0435\u0442 \u0434\u0435\u0442\u0435\u0439. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438: &quot;\u041E\u043D\u0430 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0440\u043E\u0436\u0434\u0430\u043B\u0430 \u043D\u0438 \u043E\u0434\u043D\u043E\u0439 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439!&quot; \u041F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u0435 \u0438 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C \u043F\u0440\u043E\u0441\u0442\u044B\u043C\u0438 \u0441\u043F\u043E\u0441\u043E\u0431\u0430\u043C\u0438, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0438\u043C\u0438 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430\u0445 \u0432 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435, \u043A\u0430\u043A \u044D\u0442\u043E \u043D\u0438 \u043F\u0430\u0440\u0430\u0434\u043E\u043A\u0441\u0430\u043B\u044C\u043D\u043E, \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0435\u0438\u0437\u043C\u0435\u043D\u043D\u044B\u043C\u0438. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043D\u0438 \u043E\u0434\u043D\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u043B\u0430 \u0438\u0437 \u041D\u0435\u0435, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0437\u0434\u0435\u0441\u044C \u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F/\u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F. \u042D\u0442\u0430 \u0442\u0430\u0439\u043D\u0430 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u043F\u043E\u043D\u044F\u0442\u0430 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0435\u043C\u0438, \u043A\u0442\u043E \u0431\u043B\u0430\u0433\u043E\u0441\u043B\u043E\u0432\u043B\u0435\u043D \u041C\u0438\u043B\u043E\u0441\u0442\u044C\u044E \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u042F \u043C\u043E\u0433\u0443 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u0441 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0430\u0431\u0437\u0430\u0446\u0435 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0442\u043E\u0440 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F &quot;bheda&quot;, \u0442.\u0435. \u0434\u0443\u0430\u043B\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438.</p></li><li><p>\u041D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E &quot;\u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435/\u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0435&quot;, \u043D\u043E \u0446\u0435\u043B\u044B\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u044F \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0435\u0440\u0435\u0434 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u043C Yog\u012B, \u0438 \u043E\u043D \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D &quot;\u0432\u0438\u0434\u0435\u0442\u044C&quot; \u0438\u0445, \u0433\u043E\u0432\u043E\u0440\u044F \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0445\u043E\u0442\u044F \u044D\u0442\u043E \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C\u0441\u044F \u0441\u0442\u0440\u0430\u043D\u043D\u044B\u043C \u0434\u043B\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u043B\u044E\u0434\u0435\u0439, \u043D\u043E \u043D\u043E\u0432\u044B\u0435 \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u044F, \u043F\u0438\u0441\u0430\u043D\u0438\u044F, \u043C\u0430\u043D\u0442\u0440\u044B \u0438 \u0442.\u043F. \u043D\u0435 &quot;\u0443\u0441\u043B\u044B\u0448\u0430\u043D\u044B&quot;, \u0430 &quot;\u0443\u0432\u0438\u0434\u0435\u043D\u044B&quot; \u0432\u0435\u043B\u0438\u043A\u0438\u043C Yog\u012B.</p></li><li><p>K\u1E63emar\u0101ja \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442 \u0442\u043E\u043B\u043A\u043E\u0432\u0430\u043D\u0438\u0435 \u044D\u0442\u043E\u0433\u043E 13<sup>\u043E\u0433\u043E</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E Bh\u0101skara, \u0430\u0432\u0442\u043E\u0440\u0430 \u0437\u043D\u0430\u043C\u0435\u043D\u0438\u0442\u043E\u0439 \u015Aivas\u016Btrav\u0101rttika (\u0434\u0440\u0443\u0433\u043E\u0433\u043E \u0432\u0430\u0436\u043D\u043E\u0433\u043E \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u044F \u043D\u0430 \u015Aivas\u016Btra-s): &quot;\u0907\u091A\u094D\u091B\u093E \u0936\u0915\u094D\u0924\u093F\u0924\u092E\u093E \u0915\u0941\u092E\u093E\u0930\u0940&quot; - &quot;Icch\u0101 \u015Baktitam\u0101 kum\u0101r\u012B&quot; (\u043A\u0440\u0430\u0442\u043A\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u043A\u0430\u043A &quot;\u0412\u043E\u043B\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0435\u0439 \u0421\u0438\u043B\u043E\u0439, [- \u044D\u0442\u043E] Kum\u0101r\u012B&quot;. \u0412 \u043E\u0431\u0449\u0435\u043C, \u0432 \u015Aivas\u016Btrav\u0101rttika \u0432\u044B \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u0435, \u0447\u0442\u043E \u0442\u0435\u043A\u0443\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A &quot;Icch\u0101 \u015Baktitam\u0101 kum\u0101r\u012B&quot; \u0432\u043C\u0435\u0441\u0442\u043E &quot;Icch\u0101\u015Baktirum\u0101 kum\u0101r\u012B&quot;. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0442\u0430\u043A \u043A\u0430\u043A \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0438 (\u0442.\u0435. \u015Aivas\u016Btravimar\u015Bin\u012B) \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0430\u0432\u0442\u043E\u0440\u0438\u0442\u0435\u0442\u043D\u044B\u043C, \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0432\u0435\u0440\u0441\u0438\u044E <a href="/texts/shiva-sutra">\u015Aivas\u016Btra-s</a>,</p></li><li><p>\u043A\u0430\u043A \u044D\u0442\u043E \u0434\u0430\u043D\u043E \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0435\u0439 (K\u1E63emar\u0101ja), (\u0430 \u043D\u0435 Bh\u0101skara \u0438 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0430\u0432\u0442\u043E\u0440\u0430\u043C\u0438).</p></li></ol></div>',1),o=[u];function i(p,s,k,h,c,v){return e(),m("div",null,o)}var y=a(r,[["render",i]]);export{q as __pageData,y as default};
